#include <unordered_map>
#include <vector>

using namespace std;

const long long MOD = 1e9 + 7;
const long long inv2 = 500000004;

long long solve(vector<vector<long long>> points) {
    unordered_map<long long, int> y_counts;
    for (const auto& p : points) {
        y_counts[p[1]]++;
    }

    long long S = 0;
    long long T = 0;

    for (const auto& [y, cnt] : y_counts) {
        long long term = cnt * (cnt - 1);
        term = term % MOD;
        term = term * inv2 % MOD;
        S = (S + term) % MOD;

        long long term2 = term * term % MOD;
        T = (T + term2) % MOD;
    }

    long long numerator = (S * S - T) % MOD;
    if (numerator < 0) numerator += MOD;
    long long ans = (numerator * inv2) % MOD;

    return ans;
}
